INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224318, 'Jana Hudák', '174', 'Pri oprave plota okolo pasienku sa pokazila zváračka, ktorú máme požičanú zo skladu v obci, iskrí a vypína sa sama po pár sekundách prevádzky. Potrebujeme ju dokončiť pred príchodom zimy, preto prosím o rýchle riešenie.', '2026-01-10 08:51:01+00', 'Terchová') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224319, 'Jana Hudák', '174', 'Elektrocentrála, ktorú používame pri výpadkoch prúdu na farme, sa nedá naštartovať už tretí deň, skúšali sme aj s novou batériou. Bez nej nevieme v prípade výpadku zabezpečiť napájanie pre dojáreň, čo je pri tomto počte kusov dobytka vážny problém.', '2025-09-22 05:22:40+00', 'Blatnica') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224320, 'Jana Hudák', '174', 'Hydraulika na vlečke, ktorú používame pri zvoze dreva z lesa nad obcou, prestala držať tlak, rameno samo klesá a hrozí, že spadne náklad. Prosím o čo najrýchlejšiu opravu, lebo bez vlečky sa nedá pokračovať vo zvoze.', '2026-01-10 11:02:37+00', 'Turzovka') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224321, 'Jana Hudák', '174', 'Pri oprave plota okolo pasienku sa pokazila zváračka, ktorú máme požičanú zo skladu v obci, iskrí a vypína sa sama po pár sekundách prevádzky. Potrebujeme ju dokončiť pred príchodom zimy, preto prosím o rýchle riešenie.', '2026-06-08 09:30:48+00', 'Sihelné') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224322, 'Jana Hudák', '174', 'Elektrocentrála, ktorú používame pri výpadkoch prúdu na farme, sa nedá naštartovať už tretí deň, skúšali sme aj s novou batériou. Bez nej nevieme v prípade výpadku zabezpečiť napájanie pre dojáreň, čo je pri tomto počte kusov dobytka vážny problém.', '2025-12-11 13:13:30+00', 'Vysoká nad Kysucou') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224323, 'Jana Hudák', '174', 'Dodávka, ktorou vozíme materiál medzi prevádzkou a skladom v susednej obci, má počas jazdy problém s bŕzdami, pri väčšej rýchlosti sa auto ťahá na jednu stranu. Nechceme to riskovať na horských cestách, radšej to nahlasujem hneď, ako sa to prejavilo.', '2026-01-19 13:20:15+00', 'Mútne') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224324, 'Jana Hudák', '174', 'Kúrenie v maštali prestalo fungovať práve počas silných mrazov, kotol na tuhé palivo nechce poriadne horieť a teplota v priestore pre mladý dobytok klesá pod bezpečnú hranicu, prosím o čo najrýchlejší zásah.', '2026-03-24 07:38:22+00', 'Folkušová') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224325, 'Jana Hudák', '174', 'Sejačka, ktorú sme si objednali na tento týždeň kvôli jarnej sejbe, má pri prevoze poškodené koleso, náprava je viditeľne skrivená po prejazde nerovným poľným chodníkom. Bez opravy nestíhame naplánovaný termín sejby.', '2026-03-30 10:21:02+00', 'Terchová') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224326, 'Jana Hudák', '174', 'Chladiaci box na mlieko v maštali počas letných horúčav prestáva dostatočne chladiť a teplota v ňom stúpa nad bezpečnú hranicu, čo ohrozuje kvalitu mlieka pred odvozom, prosím o urýchlené riešenie ešte pred ďalším nadojom.', '2026-06-29 09:30:05+00', 'Terchová') ON CONFLICT DO NOTHING;
