INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224328, 'Jana Hudák', '174', 'Traktor Zetor pri prevoze materiálu na vzdialenejšie pole začal počas jazdy strácať výkon motora, následne sa objavil čierny dym z výfuku a stroj sme museli odstaviť. Prosím o urýchlené preverenie, keďže bez neho nevieme dokončiť práce na poliach v okolí obce.', '2025-08-04 12:05:56+00', 'Blatnica') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224329, 'Jana Hudák', '174', 'Studňa pri hospodárskej budove, z ktorej sa napája napájací žľab pre zvieratá, začala dávať výrazne menej vody ako zvyčajne a voda je zakalená. Obávame sa, že sa niečo stalo s čerpadlom alebo potrubím, prosím o obhliadku.', '2026-06-15 11:00:32+00', 'Necpaly') ON CONFLICT DO NOTHING;
