INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224413, 'Zuzana Molnár', '909', 'Chladiaci box na mlieko v maštali počas letných horúčav prestáva dostatočne chladiť a teplota v ňom stúpa nad bezpečnú hranicu, čo ohrozuje kvalitu mlieka pred odvozom, prosím o urýchlené riešenie ešte pred ďalším nadojom.', '2025-12-25 14:16:28+00', 'Podvysoká') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224414, 'Zuzana Molnár', '909', 'Sejačka, ktorú sme si objednali na tento týždeň kvôli jarnej sejbe, má pri prevoze poškodené koleso, náprava je viditeľne skrivená po prejazde nerovným poľným chodníkom. Bez opravy nestíhame naplánovaný termín sejby.', '2026-01-05 11:25:19+00', 'Rabča') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224415, 'Zuzana Molnár', '909', 'Kúrenie v maštali prestalo fungovať práve počas silných mrazov, kotol na tuhé palivo nechce poriadne horieť a teplota v priestore pre mladý dobytok klesá pod bezpečnú hranicu, prosím o čo najrýchlejší zásah.', '2026-06-08 09:35:39+00', 'Vitanová') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224416, 'Zuzana Molnár', '909', 'Pri oprave plota okolo pasienku sa pokazila zváračka, ktorú máme požičanú zo skladu v obci, iskrí a vypína sa sama po pár sekundách prevádzky. Potrebujeme ju dokončiť pred príchodom zimy, preto prosím o rýchle riešenie.', '2026-03-28 07:28:17+00', 'Turzovka') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224459, 'Roman Varga', 'EMP-728', 'Svetlo na chodbe bliká, treba vymeniť žiarivku.', '2025-12-05 10:06:02+00', 'Martin') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224417, 'Zuzana Molnár', '909', 'Chladiaci box na mlieko v maštali počas letných horúčav prestáva dostatočne chladiť a teplota v ňom stúpa nad bezpečnú hranicu, čo ohrozuje kvalitu mlieka pred odvozom, prosím o urýchlené riešenie ešte pred ďalším nadojom.', '2025-09-01 14:34:24+00', 'Diviaky nad Nitricou') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224418, 'Zuzana Molnár', '909', 'Studňa pri hospodárskej budove, z ktorej sa napája napájací žľab pre zvieratá, začala dávať výrazne menej vody ako zvyčajne a voda je zakalená. Obávame sa, že sa niečo stalo s čerpadlom alebo potrubím, prosím o obhliadku.', '2026-06-15 13:56:41+00', 'Turčianske Jaseno') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224419, 'Zuzana Molnár', '909', 'Traktor Zetor pri prevoze materiálu na vzdialenejšie pole začal počas jazdy strácať výkon motora, následne sa objavil čierny dym z výfuku a stroj sme museli odstaviť. Prosím o urýchlené preverenie, keďže bez neho nevieme dokončiť práce na poliach v okolí obce.', '2025-09-20 06:53:44+00', 'Oravská Lesná') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224420, 'Zuzana Molnár', '909', 'Sejačka, ktorú sme si objednali na tento týždeň kvôli jarnej sejbe, má pri prevoze poškodené koleso, náprava je viditeľne skrivená po prejazde nerovným poľným chodníkom. Bez opravy nestíhame naplánovaný termín sejby.', '2025-12-30 07:30:22+00', 'Oravská Lesná') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224421, 'Zuzana Molnár', '909', 'Hydraulika na vlečke, ktorú používame pri zvoze dreva z lesa nad obcou, prestala držať tlak, rameno samo klesá a hrozí, že spadne náklad. Prosím o čo najrýchlejšiu opravu, lebo bez vlečky sa nedá pokračovať vo zvoze.', '2026-02-08 07:04:37+00', 'Klin') ON CONFLICT DO NOTHING;
