INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224424, 'Zuzana Molnár', '909', 'Studňa pri hospodárskej budove, z ktorej sa napája napájací žľab pre zvieratá, začala dávať výrazne menej vody ako zvyčajne a voda je zakalená. Obávame sa, že sa niečo stalo s čerpadlom alebo potrubím, prosím o obhliadku.', '2025-12-03 15:03:52+00', 'Liesek') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224425, 'Zuzana Molnár', '909', 'Elektrocentrála, ktorú používame pri výpadkoch prúdu na farme, sa nedá naštartovať už tretí deň, skúšali sme aj s novou batériou. Bez nej nevieme v prípade výpadku zabezpečiť napájanie pre dojáreň, čo je pri tomto počte kusov dobytka vážny problém.', '2026-05-11 09:59:16+00', 'Nová Bystrica') ON CONFLICT DO NOTHING;
