INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224655, 'Silvia Kováčová', '429', 'Dodávka, ktorou vozíme materiál medzi prevádzkou a skladom v susednej obci, má počas jazdy problém s bŕzdami, pri väčšej rýchlosti sa auto ťahá na jednu stranu. Nechceme to riskovať na horských cestách, radšej to nahlasujem hneď, ako sa to prejavilo.', '2025-11-03 14:00:37+00', 'Krivá') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224656, 'Ivana Urban', '638', 'Traktor Zetor pri prevoze materiálu na vzdialenejšie pole začal počas jazdy strácať výkon motora, následne sa objavil čierny dym z výfuku a stroj sme museli odstaviť. Prosím o urýchlené preverenie, keďže bez neho nevieme dokončiť práce na poliach v okolí obce.', '2025-10-10 08:25:54+00', 'Terchová') ON CONFLICT DO NOTHING;
INSERT INTO public.reports (id, employee_name, employee_id, problem, created_at, location) VALUES (1784668224657, 'Tomáš Balog', '521', 'Pri oprave plota okolo pasienku sa pokazila zváračka, ktorú máme požičanú zo skladu v obci, iskrí a vypína sa sama po pár sekundách prevádzky. Potrebujeme ju dokončiť pred príchodom zimy, preto prosím o rýchle riešenie.', '2026-02-23 09:19:33+00', 'Stará Bystrica') ON CONFLICT DO NOTHING;
